#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
const int N=2e5+10,INF=0x7fffffff;int a[N];
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
struct Fhq
{
	struct FHQ{int l,r,val,siz,key;}t[N*20];int cnt,Rt[N],T1,T2,T3;
	inline void update(int k){t[k].siz=t[t[k].l].siz+t[t[k].r].siz+1;}
	inline int Node(int k){t[++cnt].key=rand();t[cnt].siz=1;t[cnt].val=k;return cnt;}
	void spilt(int cur,int val,int &x,int &y)
	{
		if(!cur){x=y=0;return;}
		if(t[cur].val<=val)x=cur,spilt(t[cur].r,val,t[cur].r,y),update(x);
		else y=cur,spilt(t[cur].l,val,x,t[cur].l),update(y);
	}
	int merge(int x,int y)
	{
		if(!x||!y)return x|y;
		if(t[x].key<t[y].key){t[x].r=merge(t[x].r,y);update(x);return x;}
		t[y].l=merge(x,t[y].l);update(y);return y;
	}
	int rnk(int cur,int k){spilt(Rt[cur],k-1,T1,T2);int tmp=t[T1].siz;Rt[cur]=merge(T1,T2);return tmp;}
	inline int ins(int cur,int k){spilt(Rt[cur],k,T1,T2);Rt[cur]=merge(merge(T1,Node(k)),T2);}
	inline int del(int cur,int k){spilt(Rt[cur],k,T1,T2);spilt(T1,k-1,T1,T3);Rt[cur]=merge(merge(merge(T1,t[T3].l),t[T3].r),T2);}
	inline int pre(int cur,int k){spilt(Rt[cur],k-1,T1,T2);int tmp=T1;while(t[tmp].r)tmp=t[tmp].r;Rt[cur]=merge(T1,T2);return tmp?t[tmp].val:-INF;}
	inline int suc(int cur,int k){spilt(Rt[cur],k,T1,T2);int tmp=T2;while(t[tmp].l)tmp=t[tmp].l;Rt[cur]=merge(T1,T2);return tmp?t[tmp].val:INF;}
	void print(int cur){if(!cur)return;print(t[cur].l);printf("%d ",t[cur].val);print(t[cur].r);return;}
}fhq;
struct Seg
{
	int n;inline void Init(int g){n=g;}
	void build(int l,int r,int cur)
	{
		for(int i=l;i<=r;++i)fhq.ins(cur,a[i]);if(l==r)return;
		int mid=(l+r)>>1;build(l,mid,cur<<1);build(mid+1,r,cur<<1|1);
	}
	int Pre(int l,int r,int ql,int qr,int cur,int k)
	{
		if(ql<=l&&r<=qr)return fhq.pre(cur,k);
		int mid=(l+r)>>1,res=-INF;if(ql<=mid)res=max(res,Pre(l,mid,ql,qr,cur<<1,k));
		if(qr>mid)res=max(res,Pre(mid+1,r,ql,qr,cur<<1|1,k));return res;
	}
	int Suc(int l,int r,int ql,int qr,int cur,int k)
	{
		if(ql<=l&&r<=qr)return fhq.suc(cur,k);
		int mid=(l+r)>>1,res=INF;if(ql<=mid)res=min(res,Suc(l,mid,ql,qr,cur<<1,k));
		if(qr>mid)res=min(res,Suc(mid+1,r,ql,qr,cur<<1|1,k));return res;
	}
	int Rnk(int l,int r,int ql,int qr,int cur,int k)
	{
		if(ql<=l&&r<=qr)return fhq.rnk(cur,k);
		int mid=(l+r)>>1,res=0;if(ql<=mid)res+=Rnk(l,mid,ql,qr,cur<<1,k);
		if(qr>mid)res+=Rnk(mid+1,r,ql,qr,cur<<1|1,k);return res;
	}
	void Fxd(int l,int r,int pos,int cur,int lst,int nxt)
	{
		fhq.del(cur,lst);fhq.ins(cur,nxt);if(l==r)return;int mid=(l+r)>>1;
		if(pos<=mid)Fxd(l,mid,pos,cur<<1,lst,nxt);else Fxd(mid+1,r,pos,cur<<1|1,lst,nxt);
	}
	inline int rnk(int l,int r,int k){return Rnk(1,n,l,r,1,k)+1;}
	inline int pre(int l,int r,int k){return Pre(1,n,l,r,1,k);}
	inline int suc(int l,int r,int k){return Suc(1,n,l,r,1,k);}
	inline int kth(int L,int R,int k)
	{
		int l=-1e8,r=1e8,res=0,mid=(l+r)>>1;
		while(l<=r)rnk(L,R,mid=(l+r)>>1)<=k?(l=mid+1,res=mid):(r=mid-1);return res;
	}
	inline void fxd(int pos,int lst,int nxt){Fxd(1,n,pos,1,lst,nxt);}
}seg;
int main()
{
	int n=read(),m=read();rep(1,n,i)a[i]=read();seg.Init(n);seg.build(1,n,1);
//	fhq.del(1,4);fhq.print(fhq.Rt[1]);puts("");
//	rep(1,n,i)printf("%d ",a[i]);puts("");
//	fhq.print(1);puts("");
//	printf("%d\n",seg.rnk(1,4,4));
	rep(1,m,i)
	{
		int opt=read(),l,r,k;switch(opt)
		{
			case 1: l=read();r=read();printf("%d\n",seg.rnk(l,r,read()));break;
			case 2: l=read();r=read();printf("%d\n",seg.kth(l,r,read()));break;
			case 3: l=read();seg.fxd(l,a[l],k=read());a[l]=k;break;
			case 4: l=read();r=read();printf("%d\n",seg.pre(l,r,read()));break;
			case 5: l=read();r=read();printf("%d\n",seg.suc(l,r,read()));break;
		}
//		fhq.print(fhq.Rt[1]);puts("");
	}
}
